mapper.select:
SELECT

FROM
BPM_BUSINESS_CONFIG


        AND BUSINESS_ID = #{businessId, jdbcType=BIGINT}


        AND BUSINESS_NAME LIKE '%' || #{businessName, jdbcType=VARCHAR} || '%'


        AND BUSINESS_TYPE_CODE = #{businessTypeCode, jdbcType=VARCHAR}


        AND BUSINESS_TYPE_NAME LIKE '%' || #{businessTypeName, jdbcType=VARCHAR} || '%'


        AND PROC_MODEL_ID = #{procModelId, jdbcType=VARCHAR}


        AND PROC_MODEL_NAME LIKE '%' || #{procModelName, jdbcType=VARCHAR} || '%'


        AND PROC_DEF_ID = #{procDefId, jdbcType=VARCHAR}


        AND STATUS = #{status, jdbcType=VARCHAR}


ORDER BY
CREATE_TIME DESC
